// Premium template presets.
//
// Thumbnails are auto-generated by the Playwright thumbnail mini-service
// (mini-services/thumbnail-service) which renders each template with a
// sample resume and screenshots it at A4 ratio. They live in
// /public/thumbnails/{template-id}.png and are 100% accurate to the
// actual rendered output.
//
// To regenerate all thumbnails:
//   bun run /home/z/my-project/scripts/generate-thumbnails.ts

export interface PremiumTemplatePreset {
  id: string;
  name: string;
  description: string;
  base: string; // template id dispatched by ResumePreview
  accent: string;
  font: "sans" | "serif" | "mono";
  thumbnail: string; // image path in /thumbnails/
  category: "premium" | "pro" | "tech" | "luxury" | "designer";
  premium: true;
}

